#include <stdio.h>
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int A[N][M], dp[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &A[i][j]);
                dp[i][j] = 0;
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (i == 0 && j == 0) {
                    dp[i][j] = A[i][j];
                } else if (i == 0) {
                    dp[i][j] = dp[i][j-1] + A[i][j];
                } else if (j == 0) {
                    dp[i][j] = dp[i-1][j] + A[i][j];
                } else {
                    dp[i][j] = (dp[i-1][j] > dp[i][j-1] ? dp[i-1][j] : dp[i][j-1]) + A[i][j];
                }
            }
        }
        printf("%d\n", dp[N-1][M-1]);
    }
    return 0;
}

