const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    const A = [];
    for (let j = 0; j < N; j++) {
        A.push(readline().split(' ').map(Number));
    }
    const dp = Array(N).fill().map(() => Array(M).fill(0));
    for (let j = 0; j < N; j++) {
        for (let k = 0; k < M; k++) {
            if (j === 0 && k === 0) {
                dp[j][k] = A[j][k];
            } else if (j === 0) {
                dp[j][k] = dp[j][k-1] + A[j][k];
            } else if (k === 0) {
                dp[j][k] = dp[j-1][k] + A[j][k];
            } else {
                dp[j][k] = (dp[j-1][k] > dp[j][k-1] ? dp[j-1][k] : dp[j][k-1]) + A[j][k];
            }
        }
    }
    console.log(dp[N-1][M-1]);
